python3 - <<'PY'
import json, hashlib

# Load the macro preview
with open("eval-log/run-dev-graph-decompose-macro-preview.json") as f:
    preview = json.load(f)

# Build adjacency list from edges (depends_on only, not architecture_ref)
nodes = {}
for n in preview["decomposition"]["architecture_nodes"]:
    nodes[n["graph_node_id"]] = {"kind": n["artifact_kind"], "depends_on": n["depends_on"]}
for n in preview["decomposition"]["feature_nodes"]:
    nodes[n["graph_node_id"]] = {"kind": n["artifact_kind"], "depends_on": n["depends_on"]}

# 1. Cycle detection (DFS)
def has_cycle(graph):
    WHITE, GRAY, BLACK = 0, 1, 2
    color = {n: WHITE for n in graph}
    def dfs(u):
        color[u] = GRAY
        for v in graph[u]["depends_on"]:
            if v not in color:
                continue
            if color[v] == GRAY:
                return True
            if color[v] == WHITE and dfs(v):
                return True
        color[u] = BLACK
        return False
    return any(dfs(n) for n in graph if color[n] == WHITE)

cycle_found = has_cycle(nodes)
print(f"Cycle check: {'FAIL - cycle detected' if cycle_found else 'PASS - no cycles'}")

# 2. Task granularity mixing check
task_mixing = any(n["kind"] == "task" for n in nodes.values())
print(f"Task granularity mixing: {'FAIL - task nodes found' if task_mixing else 'PASS - no task nodes in macro DAG'}")

# 3. All nodes are draft
all_draft = True
for n in preview["decomposition"]["architecture_nodes"] + preview["decomposition"]["feature_nodes"]:
    if n["confirmation_status"] != "draft":
        all_draft = False
        break
print(f"All nodes draft: {'PASS' if all_draft else 'FAIL'}")

# 4. All tracker_binding = none
all_none = True
for n in preview["decomposition"]["architecture_nodes"] + preview["decomposition"]["feature_nodes"]:
    if n["tracker_binding"] != "none":
        all_none = False
        break
print(f"All tracker_binding=none: {'PASS' if all_none else 'FAIL'}")

# 5. Node count
arch_count = len(preview["decomposition"]["architecture_nodes"])
feat_count = len(preview["decomposition"]["feature_nodes"])
print(f"Node count: {arch_count} architecture + {feat_count} features = {arch_count + feat_count} total")

# 6. Feature required fields check
required_feature_fields = ["purpose", "goal", "scope_in", "scope_out", "acceptance", "architecture_refs"]
for n in preview["decomposition"]["feature_nodes"]:
    missing = [f for f in required_feature_fields if not n.get(f)]
    if missing:
        print(f"  FAIL: {n['graph_node_id']} missing: {missing}")
    else:
        print(f"  PASS: {n['graph_node_id']} has all required feature fields")

print("\n=== MACRO DAG VALIDATION SUMMARY ===")
if not cycle_found and not task_mixing and all_draft and all_none:
    print("ALL CHECKS PASSED")
else:
    print("SOME CHECKS FAILED")
PY

